// Pull both `forall|v|` ensures-conjuncts into the proof context so their
// (auto-picked) triggers line up across the two parallel runs.
assert(forall|v: T| #![auto]
    pre_self_@.contains(v) ==>
        pre_self_.get_node_ref(v) == post1_self_.get_node_ref(v));
assert(forall|v: T| #![auto]
    pre_self_@.contains(v) ==>
        pre_self_.get_node_ref(v) == post2_self_.get_node_ref(v));

// Combine pointwise: for every value already present in pre_self_, the two
// post-states agree on get_node_ref.
assert forall|v: T| pre_self_@.contains(v) implies
    post1_self_.get_node_ref(v) == post2_self_.get_node_ref(v) by {
    // Discharged directly by the two asserts above (transitivity through pre_self_).
};

// Both post-views are forced to pre_self_@.push(new_value); lift to extensional
// sequence equality so z3 sees a single shared spec_seq.
assert(post1_self_@ == pre_self_@.push(new_value));
assert(post2_self_@ == pre_self_@.push(new_value));
assert(post1_self_@ =~= post2_self_@);

// Lengths are pinned to pre_self_.len() + 1 in both runs.
assert(post1_self_.len() == pre_self_.len() + 1);
assert(post2_self_.len() == pre_self_.len() + 1);
assert(post1_self_.len() == post2_self_.len());

// For new_value (which is fresh in pre_self_), the two ensures pin r1 / r2 to
// post1_self_.get_node_ref(new_value) / post2_self_.get_node_ref(new_value);
// surface this so z3 has a direct handle on r1 and r2 rather than only the
// uninterpreted get_node_ref applications.
assert(post1_self_.get_node_ref(new_value) == r1);
assert(post2_self_.get_node_ref(new_value) == r2);
